"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const phrases=["Make the boundary clear","then leave room","for the next reader"];
export default function StaggeredQuoteEmphasis(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">editorial note</p><blockquote className="mt-4 text-xl leading-snug text-[#111]">{phrases.map((phrase,i)=><motion.span key={phrase} animate={{fontWeight:active===i?900:500,opacity:active===i?1:.62,y:active===i?-2:0}} transition={{duration:reduced?.12:.16}} className="mr-1 inline-block">{active===i&&<motion.i aria-hidden layoutId="quote-bracket" className="mr-1 inline-block h-5 w-1 rounded bg-[#c5bff0]"/>}{phrase}</motion.span>)}</blockquote><div aria-label="Choose emphasized phrase" className="mt-4 grid gap-2">{phrases.map((phrase,i)=><button key={phrase} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} className="min-h-11 rounded-xl border border-[#ececee] px-3 text-left text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">Emphasize: {i+1}</button>)}</div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Emphasis is on “{phrases[active]}”.</p></section>}
